 * This is the simplest way to create custom outbound policies without extending a class.
 *
 * @param response - The outgoing Response from the handler
 * @param request - The original incoming Request
 * @param context - The current context of the Request
 * @param options - The configuration options for the policy
 * @param policyName - The name set on the policy in the configuration
 * @returns A modified Response object
 *
 * @public
 * @example
 * ```typescript
 * import { OutboundPolicyHandler } from "@zuplo/runtime";
 *
 * interface CacheControlOptions {
 *   maxAge: number;
 *   sMaxAge?: number;
 *   public?: boolean;
 * }
 *
 * export const cacheControlPolicy: OutboundPolicyHandler<CacheControlOptions> = async (
 *   response,
 *   request,
 *   context,
 *   options
 * ) => {
 *   // Only cache successful responses
 *   if (response.status !== 200) {
 *     return response;
 *   }
 *
 *   // Build cache control header
 *   const directives = [`max-age=${options.maxAge}`];
 *   if (options.sMaxAge !== undefined) {
 *     directives.push(`s-maxage=${options.sMaxAge}`);
 *   }
 *   if (options.public) {
 *     directives.push("public");
 *   }
 *
 *   // Clone and modify response
 *   const newResponse = new Response(response.body, response);
 *   newResponse.headers.set("Cache-Control", directives.join(", "));
 *
 *   return newResponse;
 * };
 * ```
 */
export declare interface OutboundPolicyHandler<TOptions = any> {
  (
    response: Response,
    request: ZuploRequest,
    context: ZuploContext,
    options: TOptions,
    policyName: string
  ): Promise<Response>;
}

/**
 * Base object for parameter definitions
 * @public

import { Handler, ServiceProviderImpl } from "@zuplo/runtime";
import routeLoader from "zuplo:routes";
import * as schemaValidations from "zuplo:schema-validations";
import { runtimeInit } from "zuplo:runtime-extension";
import runtimeSettings from "zuplo:runtime-settings";
import buildEnvironment from "./build.json";

// Instantiate services
const serviceProvider = new ServiceProviderImpl();

// This is needed because we are using worker script (instead of module)
// And we need to make this available outside of this file.
globalThis["__ZUPLO_SERVICE_PROVIDER"] = serviceProvider;

const handler = new Handler(
  routeLoader,
  buildEnvironment,
  runtimeSettings,
  serviceProvider,
  schemaValidations,
  runtimeInit
);

export default {
  fetch(request, env, ctx) {
    return handler.requestHandler(request, env, ctx)
  },
};

